/**
 * Hook for Airtable operations.
 *
 * @example
 * const { listRecords } = useAirtable()
 * await listRecords('baseId', 'tableName')
 */
export function useAirtable() {
  const { callService, ...rest } = useKgoose()
  return {
    ...rest,
    listRecords: (baseId: string, tableId: string) =>
      callService(`https://api.airtable.com/v0/${baseId}/${tableId}`, 'airtable'),
    createRecord: (baseId: string, tableId: string, fields: Record<string, unknown>) =>
      callService(`https://api.airtable.com/v0/${baseId}/${tableId}`, 'airtable', { records: [{ fields }] }),
  }
}

/**
 * Generic hook for any external service.
 *
 * @example
 * const pd = useProvider('pagerduty', 'https://api.pagerduty.com')
 * await pd.get('/services')
 */
export function useProvider(extension: string, baseUrl: string) {
  const { callService, ...rest } = useKgoose()
  const base = new URL(baseUrl)
  const resolve = (path: string) => {
    const u = new URL(path, base)
    if (u.origin !== base.origin) {
      throw new Error('Path must be relative to baseUrl (origin mismatch)')
    }
    return u.href
  }
  return {
    ...rest,
    get: <T = unknown>(path: string) =>
      callService(resolve(path), extension) as Promise<T>,
    post: <T = unknown>(path: string, body: Record<string, unknown>) =>
      callService(resolve(path), extension, body) as Promise<T>,
  }
}

export default useKgoose
